import java.io.*;

public class Main {
    private static final class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            // skip non-digit, non-minus characters (including backslash, letters, spaces, newlines)
            do {
                c = readByte();
                if (c == -1) return Long.MIN_VALUE; // end of stream
            } while ((c < '0' || c > '9') && c != '-');
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = readByte();
            }
            long val = 0;
            while (c >= '0' && c <= '9') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        long tLong = fs.nextLong();
        if (tLong == Long.MIN_VALUE) return; // no input
        int T = (int) tLong;
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            long A = fs.nextLong();
            long B = fs.nextLong();
            long ans;
            if (A == B) {
                ans = 0;
            } else if (B == 0) {
                ans = -1;
            } else if (B == 1) {
                ans = (A == 0) ? 1 : -1;
            } else {
                int aa = Long.bitCount(A);
                int bb = Long.bitCount(B - 1);
                if (aa > bb) ans = -1;
                else ans = bb - aa + 1;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

